import React, { useState, useEffect } from "react";
import "./Domains.css";

const STORAGE_KEY = "domains";

const DomainsList = () => {

  const [domains, setDomains] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);

  const [domain, setDomain] = useState({
    name: "",
    description: "",
  });


  /* ===========================
        LOAD FROM localStorage
  =========================== */
  useEffect(() => {

    const stored =
      JSON.parse(localStorage.getItem(STORAGE_KEY)) ||
      [
        { id: 1, name: "IT", description: "Handles technical operations" },
        { id: 2, name: "HR", description: "Manages employees & HR operations" },
        { id: 3, name: "Finance", description: "Handles accounts & payroll" },
      ];

    setDomains(stored);

    localStorage.setItem(STORAGE_KEY, JSON.stringify(stored));

  }, []);



  /* ===========================
        SAVE HELPER
  =========================== */
  const saveToStorage = (data) => {

    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));

    setDomains(data);

  };



  /* ===========================
        INPUT CHANGE
  =========================== */
  const handleChange = (e) => {

    setDomain({
      ...domain,
      [e.target.name]: e.target.value,
    });

  };



  /* ===========================
        ADD NEW DOMAIN
  =========================== */
  const handleAdd = () => {

    setDomain({
      name: "",
      description: "",
    });

    setEditingId(null);

    setShowForm(true);

  };



  /* ===========================
        EDIT DOMAIN
  =========================== */
  const handleEdit = (dom) => {

    setDomain({
      name: dom.name,
      description: dom.description,
    });

    setEditingId(dom.id);

    setShowForm(true);

  };



  /* ===========================
        SAVE (ADD / UPDATE)
  =========================== */
  const handleSubmit = (e) => {

    e.preventDefault();

    if (!domain.name.trim()) {

      alert("Domain Name is required");

      return;

    }

    let updated;

    if (editingId) {

      updated = domains.map((d) =>
        d.id === editingId
          ? {
              ...d,
              name: domain.name,
              description: domain.description,
            }
          : d
      );

    }
    else {

      updated = [
        ...domains,
        {
          id: Date.now(),
          name: domain.name,
          description: domain.description,
        },
      ];

    }

    saveToStorage(updated);

    setShowForm(false);

  };



  /* ===========================
        DELETE DOMAIN
  =========================== */
  const handleDelete = (id) => {

    if (window.confirm("Are you sure to delete this domain?")) {

      const updated = domains.filter((d) => d.id !== id);

      saveToStorage(updated);

    }

  };



  return (

    <div className="department-scope">

      <h2>Manage Domains</h2>

      <button
        className="add-btn"
        onClick={handleAdd}
      >
        Add New Domain
      </button>



      {/* TABLE */}
      <div className="department-table-card">

        <table className="department-table">

          <thead>

            <tr>
              <th>S No</th>
              <th>Domain Name</th>
              <th>Description</th>
              <th>Action</th>
            </tr>

          </thead>



          <tbody>

            {domains.map((dom, index) => (

              <tr key={dom.id}>

                <td>{index + 1}</td>

                <td>{dom.name}</td>

                <td>{dom.description}</td>

                <td>

                  <button
                    className="edit-btn"
                    onClick={() => handleEdit(dom)}
                  >
                    Edit
                  </button>


                  <button
                    className="delete-btn"
                    onClick={() => handleDelete(dom.id)}
                  >
                    Delete
                  </button>

                </td>

              </tr>

            ))}



            {domains.length === 0 && (

              <tr>

                <td colSpan="4" style={{ textAlign: "center" }}>
                  No Domains Found
                </td>

              </tr>

            )}

          </tbody>

        </table>

      </div>



      {/* FORM */}
      {showForm && (

        <div className="add-department-card">

          <h3>
            {editingId ? "Edit Domain" : "Add New Domain"}
          </h3>



          <form
            className="add-department-form"
            onSubmit={handleSubmit}
          >

            <div className="form-group">

              <label>Domain Name</label>

              <input
                type="text"
                name="name"
                value={domain.name}
                onChange={handleChange}
                placeholder="Enter domain name"
                required
              />

            </div>



            <div className="form-group">

              <label>Description</label>

              <textarea
                name="description"
                value={domain.description}
                onChange={handleChange}
                placeholder="Enter description"
              />

            </div>



            <div className="form-actions">

              <button type="submit" className="save-btn">
                {editingId ? "Update" : "Save"}
              </button>



              <button
                type="button"
                className="cancel-btn"
                onClick={() => setShowForm(false)}
              >
                Cancel
              </button>

            </div>

          </form>

        </div>

      )}

    </div>

  );

};

export default DomainsList;
